const body = $input.first().json.body ?? $input.first().json;
const objects = body.objects ?? [];

function depthPhrase(depth) {
  const map = {
    very_near: 'very close to you',
    near: 'close to you',
    medium: 'at a medium distance',
    far: 'far away'
  };
  return map[depth] ?? depth;
}

function horizontalPhrase(h) {
  if (h === 'left') return 'on your left';
  if (h === 'right') return 'on your right';
  return 'directly in front of you';
}

function describe(obj) {
  const name = (obj.display_name || obj.label || 'object').replace(/_/g, ' ');
  const pos = obj.position || {};
  return `${name}, ${depthPhrase(pos.depth)}, ${horizontalPhrase(pos.horizontal)}`;
}

let spatial_sentence;

if (objects.length === 0) {
  spatial_sentence = 'I do not see any recognizable objects in front of you.';
} else if (objects.length === 1) {
  spatial_sentence = `I see ${describe(objects[0])}.`;
} else {
  const parts = objects.slice(0, 5).map(describe);
  const last = parts.pop();
  spatial_sentence = `I see ${parts.join('; ')}, and ${last}.`;
}

return [{
  json: {
    spatial_sentence,
    object_count: objects.length,
    received_at: new Date().toISOString(),
    source: body.source ?? 'unknown'
  }
}];
